select id,
       category_id,
       label_id,
       sort_num,
       created_by,
       created_time,
       update_by,
       update_time,
       is_deleted
from subject_category_label


        and id = #{id}


        and category_id = #{categoryId}


        and label_id = #{labelId}


        and sort_num = #{sortNum}


        and is_deleted = #{isDeleted}


order by sort_num asc, id asc

